VALUES
  ('elementary-0a2fc18c-moex-00603', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '近年來，臺灣多起隨機殺人案件引發社會關注，而部分加害者因罹患思覺失調症而獲判無罪，判決或辯 護理由常引發媒體與大眾的議論。但法治國家就是要在正當法律程序下仔細分析罪犯的動機和成因，律 師的角色是在維護被告基本訴訟權利不被侵犯，而法官則是依法公正審判。若從人權的角度出發，上述 內容是在強調何種權利保障的重要性？', '["行動自由", "公民參政", "社會安全", "公正審判"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:17+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00604', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '我國「彈劾權」的設計，與三權分立的國家略有不同。關於我國彈劾權的行使，下列何者正確？', '["立法院可以對行政院院長提出彈劾案", "立法院可調查且彈劾違法的公務人員", "監察院可對違法失職的總統或副總統進行彈劾", "監察院可彈劾縣、市首長並移送司法懲戒"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:17+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00605', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '我國自1991年至2005年共經歷七次憲法增修，下列何者為修憲的成果？', '["憲法修正案及領土變更案須經人民連署提案", "命令或法律有違憲之虞者由大法官進行解釋", "正副總統彈劾案由立法院提案，憲法法庭審理", "各縣市的縣市長及縣市議員，皆改由人民直選"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:17+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00606', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '關於我國近年來憲法的變遷與成長，下列敘述何者正確？', '["憲法修正案經公民複決，有效同意票過選舉人總額之半數即通過", "憲法修正案經公民複決程序，通過門檻與全國性公民投票案相同", "除立法院外，公民亦可經全國性公民投票程序，提出憲法修正案", "司法院大法官以憲法解釋的方式，來推翻不合時宜的憲法條文"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:17+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00607', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '公民投票指全體公民透過行使投票的權利，對國家或社會的重大或特定問題進行表決的制度。關於我國 公民投票的制度與實施，下列何者最為適切？', '["每一年皆可舉行一次公民投票", "投票資格與正副總統選舉相同", "展現國民主權", "保護社會上少數人的權益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:17+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00608', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '基於民主政治的理念，為確保人民意見得以有效影響國家權力，成為政府決策時考量的重要因素，下列 敘述何者正確？', '["人民發表任何政治性言論，均得免除刑事責任", "政府機關制定政策時，須舉辦全國性民意調查為參考依據", "外國籍人士一旦獲得永久居留權，依法應賦予選舉權利", "政府應依法保障人民合法的集會遊行活動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:17+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00609', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '依據憲法增修條文規定，行政院院長之任命，已無須再經立法院同意，惟立法院得以下述何種法定程序 使行政院院長去職？', '["立法委員連署對行政院院長提出不信任案，經全體立法委員二分之一以上贊成後通過", "立法委員號召選民連署通過後，以相對多數投票罷免行政院院長", "立法委員連署聲請司法院大法官召開憲法法庭，宣告行政院院長解職", "立法委員以三分之二多數對行政院院長行使彈劾權，使行政院院長去職"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:17+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00610', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', 'A 候選人在某次立法委員選舉中獲取該選區最高票數，並經中央選舉委員會公告當選。惟同選區競爭對 手B候選人指控，A候選人委託各里長以現金行賄選民，已掌握確切證據。依照公職人員選舉罷免法之 規定，B候選人應提起何種類型之訴訟？', '["撤銷當選公告訴訟", "選舉無效之訴", "當選無效之訴", "課予中央選舉委員會重新辦理選舉義務之訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:17+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00611', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '刑罰的目的在追求「刑期無刑」，符合以下何種刑罰目的之理論？', '["應報理論", "綜合理論", "一般預防理論", "特別預防理論"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:17+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00612', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '各國政府體制之間存在差異的程度不一，下列何者足以代表總統制國家與內閣制國家最顯著的差異？', '["對於文官體制與其中立地位的尊重", "行政權與立法權分立與制衡的程度", "其國家元首為總統或是國王", "國會機構是一院制或是兩院制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:17+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL)
